using UnityEngine;
using UnityEngine.UI;
using UnityEditor;

public class Script
{
    public static object Main()
    {
        var enemy = GameObject.Find("Enemy");
        if (enemy == null) return "Enemy not found";

        var old = enemy.transform.Find("HealthBar");
        if (old != null) GameObject.DestroyImmediate(old.gameObject);

        var canvasGO = new GameObject("HealthBar");
        canvasGO.transform.SetParent(enemy.transform, false);
        canvasGO.transform.localPosition = new Vector3(0f, 0.8f, 0f);
        canvasGO.transform.localScale = new Vector3(0.01f, 0.01f, 1f);

        var canvas = canvasGO.AddComponent<Canvas>();
        canvas.renderMode = RenderMode.WorldSpace;

        var rt = canvasGO.GetComponent<RectTransform>();
        rt.sizeDelta = new Vector2(100f, 15f);

        var bgGO = new GameObject("BG");
        bgGO.transform.SetParent(canvasGO.transform, false);
        var bgImg = bgGO.AddComponent<Image>();
        bgImg.color = new Color(0.15f, 0.15f, 0.15f, 1f);
        var bgRt = bgGO.GetComponent<RectTransform>();
        bgRt.anchorMin = Vector2.zero;
        bgRt.anchorMax = Vector2.one;
        bgRt.offsetMin = Vector2.zero;
        bgRt.offsetMax = Vector2.zero;

        var fillGO = new GameObject("Fill");
        fillGO.transform.SetParent(canvasGO.transform, false);
        var fillImg = fillGO.AddComponent<Image>();
        fillImg.color = Color.green;
        fillImg.type = Image.Type.Filled;
        fillImg.fillMethod = Image.FillMethod.Horizontal;
        fillImg.fillAmount = 1f;
        var fillRt = fillGO.GetComponent<RectTransform>();
        fillRt.anchorMin = Vector2.zero;
        fillRt.anchorMax = Vector2.one;
        fillRt.offsetMin = Vector2.zero;
        fillRt.offsetMax = Vector2.zero;

        var hb = canvasGO.AddComponent<HealthBar>();
        typeof(HealthBar).GetField("fill", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance).SetValue(hb, fillImg);
        canvasGO.AddComponent<HealthBarInit>();

        EditorUtility.SetDirty(enemy);
        return "Health bar built on Enemy";
    }
}
